#!/bin/bash
set -e

RPC=http://localhost:8545
PK=0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80
ADMIN=0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266
THRESHOLD=2
MIN_DELAY=0
SIGNER1=0xf39Fd6e51aad88F6F4ce6aB8827279cffFb92266
SIGNER2=0x70997970C51812dc3A010C7d01b50e0d17dc79C8
SIGNER3=0x3C44CdDdB6a900fa2b585dd299e03d12FA4293BC

echo "=== Starting anvil ==="
anvil --code-size-limit 50000 > /tmp/anvil.log 2>&1 &
sleep 2

echo "=== Step 1: Deploy TreasuryCore implementation ==="
forge create TreasuryCore --rpc-url $RPC --private-key $PK 2>&1 | tee /tmp/deploy-tc.log
TC_IMPL=$(grep "Deployed to" /tmp/deploy-tc.log | awk '{print $3}')
echo "TreasuryCore Impl: $TC_IMPL"

echo "=== Step 2: Deploy StreamingManager implementation ==="
forge create StreamingManager --rpc-url $RPC --private-key $PK 2>&1 | tee /tmp/deploy-sm.log
SM_IMPL=$(grep "Deployed to" /tmp/deploy-sm.log | awk '{print $3}')
echo "StreamingManager Impl: $SM_IMPL"

echo "=== Step 3: Deploy YieldManager implementation ==="
forge create YieldManager --rpc-url $RPC --private-key $PK 2>&1 | tee /tmp/deploy-ym.log
YM_IMPL=$(grep "Deployed to" /tmp/deploy-ym.log | awk '{print $3}')
echo "YieldManager Impl: $YM_IMPL"

echo "=== Step 4: Deploy ERC1967Proxy ==="
forge create ERC1967Proxy --rpc-url $RPC --private-key $PK 2>&1 | tee /tmp/deploy-proxy.log
PROXY_IMPL=$(grep "Deployed to" /tmp/deploy-proxy.log | awk '{print $3}')
echo "Proxy Template: $PROXY_IMPL"

echo ""
echo "=== Step 5: Encode initializer data ==="
# TreasuryCore.initialize(admin, signers, threshold, minDelay)
TC_INIT=$(cast calldata "initialize(address,address[],uint256,uint256)" \
  $ADMIN "[$SIGNER1,$SIGNER2,$SIGNER3]" $THRESHOLD $MIN_DELAY)
echo "TC init: $TC_INIT"

# StreamingManager.initialize(admin, treasuryProxy)
SM_INIT=$(cast calldata "initialize(address,address)" $ADMIN 0x0000000000000000000000000000000000000000)
echo "SM init: $SM_INIT"

# YieldManager.initialize(admin, treasuryProxy)
YM_INIT=$(cast calldata "initialize(address,address)" $ADMIN 0x0000000000000000000000000000000000000000)
echo "YM init: $YM_INIT"

echo ""
echo "=== Step 6: Deploy proxies ==="
# Deploy TreasuryCore proxy
echo "Deploying TreasuryCore proxy..."
DEPLOY_TC_PROXY=""

echo "TODO: deploy ERC1967Proxy with ($TC_IMPL, $TC_INIT)"

echo ""
echo "=== Summary ==="
echo "TreasuryCore Impl:  $TC_IMPL"
echo "StreamManager Impl: $SM_IMPL"
echo "YieldManager Impl:  $YM_IMPL"
